import { useState, useCallback } from 'react';
import { MOCK_FORMS, MOCK_QUESTIONS } from '../data/mockData';
import { Form, Question, Message } from '../types';

export function useFormThread() {
  const [forms] = useState<Form[]>(MOCK_FORMS);
  const [questions, setQuestions] = useState<Question[]>(
    JSON.parse(JSON.stringify(MOCK_QUESTIONS))
  );
  const [selectedFormId, setSelectedFormId] = useState<string>(MOCK_FORMS[0].id);
  const [selectedQuestionId, setSelectedQuestionId] = useState<string | null>(
    MOCK_QUESTIONS.find((q) => q.formId === MOCK_FORMS[0].id)?.id ?? null
  );
  const [activeTab, setActiveTab] = useState<'All' | 'Awaiting' | 'Answered'>('All');

  const selectedForm = forms.find((f) => f.id === selectedFormId) ?? null;

  const visibleQuestions = questions.filter((q) => {
    if (q.formId !== selectedFormId) return false;
    if (activeTab === 'Awaiting') return q.status === 'unanswered';
    if (activeTab === 'Answered') return q.status === 'answered';
    return true;
  });

  const selectedQuestion = questions.find((q) => q.id === selectedQuestionId) ?? null;

  const selectForm = useCallback(
    (formId: string) => {
      setSelectedFormId(formId);
      setActiveTab('All');
      const first = questions.find((q) => q.formId === formId);
      setSelectedQuestionId(first?.id ?? null);
    },
    [questions]
  );

  const selectQuestion = useCallback((questionId: string) => {
    setSelectedQuestionId(questionId);
    setQuestions((prev) =>
      prev.map((q) => (q.id === questionId ? { ...q, unread: false } : q))
    );
  }, []);

  const sendReply = useCallback(
    (questionId: string, content: string) => {
      if (!content.trim()) return;
      const question = questions.find((q) => q.id === questionId);
      if (!question) return;
      const form = forms.find((f) => f.id === question.formId);

      const newMessage: Message = {
        id: `m-${Date.now()}`,
        role: 'respondent',
        content: content.trim(),
        timestamp: new Date().toLocaleString('en-US', {
          month: 'short',
          day: 'numeric',
          hour: 'numeric',
          minute: '2-digit',
          hour12: true,
        }),
        senderName: form?.respondentName ?? 'Respondent',
        senderInitial: (form?.respondentName?.[0] ?? 'R').toUpperCase(),
      };

      setQuestions((prev) =>
        prev.map((q) =>
          q.id === questionId
            ? {
                ...q,
                messages: [...q.messages, newMessage],
                lastActivity: 'Just now',
                status: 'answered' as const,
                unread: false,
              }
            : q
        )
      );
    },
    [questions, forms]
  );

  const unreadCount = useCallback(
    (formId: string) => questions.filter((q) => q.formId === formId && q.unread).length,
    [questions]
  );

  return {
    forms,
    visibleQuestions,
    allQuestions: questions,
    selectedForm,
    selectedQuestion,
    selectedFormId,
    selectedQuestionId,
    activeTab,
    setActiveTab,
    selectForm,
    selectQuestion,
    sendReply,
    unreadCount,
  };
}
